using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; using Norge360.Community.Domain.Entities; namespace Norge360.Community.Infrastructure.Persistence.Configurations; public sealed class CommunityPostLikeConfiguration : IEntityTypeConfiguration<CommunityPostLike>{ public void Configure(EntityTypeBuilder<CommunityPostLike> b){ b.ToTable("CommunityPostLikes"); b.HasKey(x=>x.Id); b.HasIndex(x=>new{x.PostId,x.UserId}).IsUnique().HasFilter("\"IsDeleted\" = false"); b.HasQueryFilter(x=>!x.IsDeleted); }}
